@dataclass(frozen=True, slots=True)
class TerminalMarkers:
    terminal_url: str
    tunnel_url: str
    tmux_session_name: str


def parse_terminal_markers(stdout: str, stderr: str) -> TerminalMarkers:
    combined = f"{stdout}\n{stderr}"
    tunnel_match = _TUNNEL_RE.search(combined)
    auth_match = _AUTH_RE.search(combined)
    session_match = _TMUX_SESSION_RE.search(combined)
    if tunnel_match is None or auth_match is None or session_match is None:
        raise ValueError("terminal stdout markers missing")
    tunnel_url = tunnel_match.group(1).strip()
    auth_token = auth_match.group(1).strip()
    tmux_session_name = session_match.group(1).strip()
    if not tmux_session_name:
        raise ValueError("REBASE_TMUX_SESSION marker is empty")
    terminal_url = resolve_terminal_url(stdout=stdout, stderr=stderr, auth_token=auth_token)
    return TerminalMarkers(
        terminal_url=terminal_url,
        tunnel_url=tunnel_url,
        tmux_session_name=tmux_session_name,
    )

